import { Vex } from '@vex_dev/sdk';
import { createMastraAgent } from 'mastra';

const vex = new Vex({
  projectId: 'gov-mastra-compliance',
  environment: 'fedramp-high'
});

const mastraAgent = createMastraAgent({ /* config */ });

export async function compliantAgentExecute(input: any) {
  const span = await vex.trace('mastra-workflow', { sensitivity: 'critical' });

  try {
    const result = await mastraAgent.execute(input);
    await span.setOutput({ validated: true, citizenImpact: true });
    await vex.validateWorkflowOutput(result, {
      nistControls: ['AC-3', 'AU-6'],
      blockOnFailure: true
    });
    return result;
  } finally {
    await span.end();
  }
}

import { VexGuardrail } from '@vex_dev/sdk';

const classifiedDataGuard = new VexGuardrail({
  name: 'gov-classified-data',
  rules: [
    'NO_CLASSIFIED_DATA',
    'NO_PII_IN_TOOLS',
    'FEDRAMP_MALFORMED_RESPONSE'
  ]
});

// In Mastra tool configuration
mastraAgent.addTool({
  name: 'external-api',
  execute: async (params) => {
    await classifiedDataGuardrail.enforce(params);
    const result = await callExternalAPI(params);
    await classifiedDataGuardrail.validateOutput(result, {
      schema: 'fema-disaster-data',
      sensitivity: 'critical'
    });
    return result;
  }
});

import { Vex } from '@vex_dev/sdk';

const govVex = new Vex({ projectId: 'mastra-gov' });

mastraAgent.on('memory-retrieve', async (context) => {
  const validation = await govVex.validate({
    input: context.retrievedChunks,
    guardrail: 'gov-stale-context',
    rules: {
      freshness: '24h',
      classification: 'unclassified',
      policyVersion: 'current'
    }
  });

  if (!validation.passed) {
    console.warn('Blocked stale context:', validation.violations);
    return { chunks: [], reason: 'STALE_CONTEXT_BLOCKED' };
  }

  return context;
});
